INSERT INTO metric_definition (id, metric_key, display_name, description, formula, source_tables, inclusion_rules, exclusion_rules, unit, data_type, active) VALUES
('a0000000-0000-0000-0000-000000000210', 'net_income', 'Net Income', 'Total revenue minus total expenses', 'SUM(revenue) - SUM(expense)', ARRAY['noi_snapshot'], 'All farm revenue minus all expenses', 'Excludes initial capital investment', 'USD', 'currency', TRUE),
('a0000000-0000-0000-0000-000000000211', 'loss_rate', 'Loss Rate', 'Percentage of crop value lost', 'SUM(loss_value) / SUM(harvest_value)', ARRAY['loss_event'], 'All crop losses after harvest', 'Pre-harvest losses excluded', '%', 'percentage', TRUE),
('a0000000-0000-0000-0000-000000000212', 'revenue_per_ha', 'Revenue per Hectare', 'Revenue per hectare of farmland', 'SUM(revenue) / SUM(area_ha)', ARRAY['sales_event'], 'All crop sales', 'Non-crop revenue excluded', 'USD/hectare', 'currency', TRUE),
('a0000000-0000-0000-0000-000000000213', 'operating_margin', 'Operating Margin', 'Net income as percentage of revenue', 'NOI / REVENUE', ARRAY['noi_snapshot'], 'All farm operations', 'Capital expenditure excluded', '%', 'percentage', TRUE),
('a0000000-0000-0000-0000-000000000214', 'yield_per_ha', 'Yield per Hectare', 'Harvest yield per hectare', 'SUM(quantity) / SUM(area_ha)', ARRAY['harvest_event'], 'All harvested crops', 'Post-harvest losses excluded', 'tonnes/hectare', 'quantity', TRUE),
('a0000000-0000-0000-0000-000000000215', 'soil_organic_matter', 'Soil Organic Matter', 'Average soil organic matter percentage', 'AVG(organic_matter_pct)', ARRAY['soil_sample'], 'All soil samples', 'Abandoned plots excluded', '%', 'percentage', TRUE),
('a0000000-0000-0000-0000-000000000216', 'carbon_sequestration', 'Carbon Sequestration', 'Estimated carbon captured', 'SUM(biomass_kg) * 0.5', ARRAY['harvest_event'], 'All crop biomass', 'Non-organic inputs excluded', 'kg', 'quantity', TRUE),
('a0000000-0000-0000-0000-000000000217', 'data_completeness', 'Data Completeness', 'Percentage of expected data present', 'actual_points / expected_points', ARRAY['various'], 'All required data types', 'Optional data excluded', '%', 'percentage', TRUE),
('a0000000-0000-0000-0000-000000000218', 'revenue_growth', 'Revenue Growth', 'Month-over-month revenue change', '(current - previous) / previous', ARRAY['noi_snapshot'], 'Month-over-month comparison', 'First month excluded', '%', 'percentage', TRUE),
('a0000000-0000-0000-0000-000000000219', 'cost_per_ha', 'Cost per Hectare', 'Total expenses per hectare', 'SUM(expenses) / SUM(area_ha)', ARRAY['expense_event'], 'All farm expenses', 'Capital expenditure excluded', 'USD/hectare', 'currency', TRUE)
